## Real behavior proof

HEAD: 4c1692af39b96f4577c19b2bbf1062075e899615

```json
{
  "head": "4c1692af39b96f4577c19b2bbf1062075e899615",
  "envFlag": "OPENCLAW_ENABLE_GOOGLE_GEMINI_CLI_HARNESS",
  "cases": {
    "freshGoogleRuntimeDefaultEnvUnset": {
      "bundledRuntimePlugin": {
        "providers": [
          "google"
        ],
        "cliBackends": []
      },
      "expected": "Direct bundled runtime registration exposes google only and does not expose google-gemini-cli provider/backend by default."
    },
    "explicitGeminiCliHarnessOptIn": {
      "bundledRuntimePlugin": {
        "providers": [
          "google-gemini-cli",
          "google"
        ],
        "cliBackends": [
          {
            "id": "google-gemini-cli",
            "command": "gemini",
            "output": "jsonl",
            "jsonlDialect": "gemini-stream-json",
            "modelArg": "--model",
            "sessionMode": "existing"
          }
        ]
      },
      "expected": "Direct bundled runtime registration exposes google-gemini-cli provider/backend only when OPENCLAW_ENABLE_GOOGLE_GEMINI_CLI_HARNESS=1."
    },
    "setupCompatibilityPathEnvUnset": {
      "setupEntry": {
        "providers": [
          "google-vertex"
        ],
        "cliBackends": [
          {
            "id": "google-gemini-cli",
            "command": "gemini",
            "output": "jsonl",
            "jsonlDialect": "gemini-stream-json",
            "modelArg": "--model",
            "sessionMode": "existing"
          }
        ]
      },
      "setupRegistryGeminiCliBackend": {
        "pluginId": "google",
        "backend": {
          "id": "google-gemini-cli",
          "command": "gemini",
          "output": "jsonl",
          "jsonlDialect": "gemini-stream-json",
          "modelArg": "--model",
          "sessionMode": "existing"
        }
      },
      "expected": "Setup entry and setup-registry lookup still expose google-gemini-cli backend without the env flag for compatibility."
    }
  }
}
```

